/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:fl_chart/fl_chart.dart';
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball_info.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/ball_quality_scorer.dart';
import 'package:baseball_detector_flutter/utils/environment.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

/// Color used for grid lines and borders
const _ruleColor = Color(0xffcccccc);

/// Creates a grid line with consistent styling
FlLine ruleFunc(double value) {
  return const FlLine(
    color: _ruleColor,
    strokeWidth: 0.5,
  );
}

/// Widget that displays a ball trajectory graph showing X, Y, Z positions over time
class BallTrajectoryGraph extends HookWidget {
  const BallTrajectoryGraph({
    required this.ballInfo,
    super.key,
  });

  final BallInfo ballInfo;

  @override
  Widget build(BuildContext context) {
    final lineChartData = useMemoized(
      () => _createLineChartData(context),
      [ballInfo.positions],
    );

    final scorer = BallQualityScorer();
    final details = scorer.calculateQScoreDetailsForBall(ballInfo);

    return Card(
      child: Padding(
        padding: const EdgeInsets.all(14),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            if (details != null && (isDev || isStg))
              Container(
                margin: const EdgeInsets.only(bottom: 16),
                padding: const EdgeInsets.all(12),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    Row(
                      children: [
                        Icon(
                          Icons.sports_baseball,
                          size: 16,
                          color: Theme.of(context).colorScheme.primary,
                        ),
                        const SizedBox(width: 8),
                        Text(
                          context.l10n
                              .resource_details_page__ball_quality_total_score,
                          style: TextStyle(
                            fontSize: 14,
                            fontWeight: FontWeight.w600,
                            color: Theme.of(context).colorScheme.onSurface,
                          ),
                        ),
                        const Spacer(),
                        Container(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 8, vertical: 4),
                          decoration: BoxDecoration(
                            color: _getScoreColor(details.totalScore),
                            borderRadius: BorderRadius.circular(12),
                          ),
                          child: Text(
                            '${details.totalScore.toStringAsFixed(1)}/100',
                            style: const TextStyle(
                              fontSize: 14,
                              fontWeight: FontWeight.bold,
                              color: Colors.white,
                            ),
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 12),
                    _buildQualityDetailItem(
                      context,
                      context.l10n
                          .resource_details_page__ball_quality_detection_count,
                      Icons.grain,
                      details.sDensity,
                      details.weightedDensity,
                    ),
                    const SizedBox(height: 8),
                    _buildQualityDetailItem(
                      context,
                      context.l10n
                          .resource_details_page__ball_quality_trajectory_linearity,
                      Icons.timeline,
                      details.sLinearity,
                      details.weightedLinearity,
                    ),
                    const SizedBox(height: 8),
                    _buildQualityDetailItem(
                      context,
                      context.l10n
                          .resource_details_page__ball_quality_detection_distance,
                      Icons.open_in_full,
                      details.sRange,
                      details.weightedRange,
                    ),
                  ],
                ),
              ),
            lineChartData == null
                ? SizedBox(
                    height: 240,
                    child: Text(
                      context.l10n.ball_trajectory_graph__positions_unavailable,
                    ),
                  )
                : SizedBox(
                    height: 280,
                    width: double.infinity,
                    child: LineChart(lineChartData),
                  ),
          ],
        ),
      ),
    );
  }

  /// Creates line chart data from ball position information
  /// Returns null if positions data is unavailable
  LineChartData? _createLineChartData(BuildContext context) {
    if (ballInfo.positions == null) return null;

    // Sort positions by time to ensure proper trajectory display
    final sortedPositions = List.from(ballInfo.positions!)
      ..sort((a, b) => (a.time ?? 0).compareTo(b.time ?? 0));

    // Transform position data into chart spots declaratively
    final xSpots =
        sortedPositions.map((pos) => FlSpot(pos.time!, pos.x!)).toList();
    final ySpots =
        sortedPositions.map((pos) => FlSpot(pos.time!, pos.y!)).toList();
    final zSpots =
        sortedPositions.map((pos) => FlSpot(pos.time!, pos.z!)).toList();

    return LineChartData(
      lineTouchData: LineTouchData(
        handleBuiltInTouches: true,
        getTouchedSpotIndicator: defaultTouchedIndicators,
        touchTooltipData: LineTouchTooltipData(
          getTooltipColor: (_) => Colors.blueGrey.shade900,
          getTooltipItems: (List<LineBarSpot> touchedBarSpots) {
            final xLegend = context.l10n.ball_trajectory_graph__legend_x;
            final yLegend = context.l10n.ball_trajectory_graph__legend_y;
            final zLegend = context.l10n.ball_trajectory_graph__legend_z;
            final xUnit = context.l10n.ball_trajectory_graph__unit_x;
            final yUnit = context.l10n.ball_trajectory_graph__unit_y;
            final zUnit = context.l10n.ball_trajectory_graph__unit_z;

            touchedBarSpots.sort(((x, y) => x.barIndex - y.barIndex));
            final x = touchedBarSpots[0].y.toStringAsFixed(2);
            final y = touchedBarSpots[1].y.toStringAsFixed(2);
            final z = touchedBarSpots[2].y.toStringAsFixed(2);
            final time = touchedBarSpots[0].x.toStringAsFixed(2);
            return [
              LineTooltipItem(
                "time = $time [s]\n",
                const TextStyle(color: ColorManager.chartTooltipText),
                textAlign: TextAlign.left,
                children: [
                  TextSpan(
                    text: "$xLegend = $x $xUnit",
                    style: TextStyle(color: ColorManager.chartX),
                  ),
                ],
              ),
              LineTooltipItem(
                "$yLegend = $y $yUnit",
                TextStyle(color: ColorManager.chartY),
                textAlign: TextAlign.left,
              ),
              LineTooltipItem(
                "$zLegend = $z $zUnit",
                TextStyle(color: ColorManager.chartZ),
                textAlign: TextAlign.left,
              ),
            ];
          },
        ),
      ),
      gridData: const FlGridData(
        horizontalInterval: 5.0,
        verticalInterval: 0.1,
        getDrawingHorizontalLine: ruleFunc,
        getDrawingVerticalLine: ruleFunc,
      ),
      titlesData: const FlTitlesData(
        show: true,
        bottomTitles: AxisTitles(
          sideTitles: SideTitles(
            showTitles: true,
            interval: 0.1,
            reservedSize: 40,
            minIncluded: false,
            maxIncluded: false,
          ),
        ),
        leftTitles: AxisTitles(
          sideTitles: SideTitles(
            showTitles: true,
            interval: 5,
            reservedSize: 40,
            minIncluded: false,
            maxIncluded: false,
          ),
        ),
        topTitles: AxisTitles(
          sideTitles: SideTitles(showTitles: false),
        ),
        rightTitles: AxisTitles(
          sideTitles: SideTitles(showTitles: false),
        ),
      ),
      borderData: FlBorderData(
        show: true,
        border: Border.all(
          color: _ruleColor,
        ),
      ),
      // Create line chart bars inline with consistent styling
      lineBarsData: [
        LineChartBarData(
          spots: xSpots,
          color: ColorManager.chartX,
          isCurved: false,
          barWidth: 1.0,
          isStrokeCapRound: false,
          dotData: FlDotData(
            show: true,
            getDotPainter: (spot, percent, barData, index) =>
                FlDotCirclePainter(
              radius: 1.5,
              color: ColorManager.chartX,
              strokeWidth: 2.0,
              strokeColor: ColorManager.chartX,
            ),
          ),
          belowBarData: BarAreaData(show: false),
        ),
        LineChartBarData(
          spots: ySpots,
          color: ColorManager.chartY,
          isCurved: false,
          barWidth: 1.0,
          isStrokeCapRound: false,
          dotData: FlDotData(
            show: true,
            getDotPainter: (spot, percent, barData, index) =>
                FlDotCirclePainter(
              radius: 1.5,
              color: ColorManager.chartY,
              strokeWidth: 2.0,
              strokeColor: ColorManager.chartY,
            ),
          ),
          belowBarData: BarAreaData(show: false),
        ),
        LineChartBarData(
          spots: zSpots,
          color: ColorManager.chartZ,
          isCurved: false,
          barWidth: 1.0,
          isStrokeCapRound: false,
          dotData: FlDotData(
            show: true,
            getDotPainter: (spot, percent, barData, index) =>
                FlDotCirclePainter(
              radius: 1.5,
              color: ColorManager.chartZ,
              strokeWidth: 2.0,
              strokeColor: ColorManager.chartZ,
            ),
          ),
          belowBarData: BarAreaData(show: false),
        ),
      ],
    );
  }

  Widget _buildQualityDetailItem(
    BuildContext context,
    String label,
    IconData icon,
    double score,
    double weightedScore,
  ) {
    final percentage = (score * 100).toStringAsFixed(1);
    final weightedPercentage = (weightedScore * 100).toStringAsFixed(1);

    return Row(
      children: [
        Icon(
          icon,
          size: 14,
          color: Theme.of(context).colorScheme.onSurfaceVariant,
        ),
        const SizedBox(width: 8),
        SizedBox(
          width: 80,
          child: Text(
            label,
            style: TextStyle(
              fontSize: 12,
              color: Theme.of(context).colorScheme.onSurfaceVariant,
            ),
          ),
        ),
        const SizedBox(width: 8),
        Expanded(
          child: LinearProgressIndicator(
            value: score,
            backgroundColor:
                Theme.of(context).colorScheme.outline.withValues(alpha: 0.2),
            valueColor: AlwaysStoppedAnimation<Color>(
              _getScoreColor(score * 100),
            ),
          ),
        ),
        const SizedBox(width: 8),
        Text(
          context.l10n
              .resource_details_page__ball_quality_percentage_with_weight(
            percentage,
            weightedPercentage,
          ),
          style: TextStyle(
            fontSize: 11,
            color: Theme.of(context).colorScheme.onSurfaceVariant,
          ),
        ),
      ],
    );
  }

  Color _getScoreColor(double score) {
    if (score >= 80) return Colors.green;
    if (score >= 60) return Colors.orange;
    if (score >= 40) return Colors.amber;
    return Colors.red;
  }
}

