    84→    if (z.length != t.length || z.isEmpty) {
    85→      return const QScoreDetails(
    86→        sDensity: 0.0,
    87→        sLinearity: 0.0,
    88→        sRange: 0.0,
    89→        weightedDensity: 0.0,
    90→        weightedLinearity: 0.0,
    91→        weightedRange: 0.0,
    92→        totalScore: 0.0,
    93→      );
    94→    }
    95→
