   105→    // 3. z 軸変位
   106→    final dz = z.reduce(max) - z.reduce(min);
   107→    final sRange = _calculateSRange(dz);
   108→
   109→    // 各スコアの最小値を0にクランプ
   110→    final clampedSDensity = sDensity.clamp(0.0, 1.0);
   111→    final clampedSLinearity = sLinearity.clamp(0.0, 1.0);
   112→    final clampedSRange = sRange.clamp(0.0, 1.0);
   113→
   114→    // 重み付けスコア
   115→    final weightedDensity = p.wDensity * clampedSDensity;
   116→    final weightedLinearity = p.wLinearity * clampedSLinearity;
   117→    final weightedRange = p.wRange * clampedSRange;
   118→
   119→    // 総合スコア（0–100）
   120→    final totalScore =
   121→        (weightedDensity + weightedLinearity + weightedRange) * 100;
   122→
   123→    return QScoreDetails(
   124→      sDensity: clampedSDensity,
   125→      sLinearity: clampedSLinearity,
   126→      sRange: clampedSRange,
   127→      weightedDensity: weightedDensity,
   128→      weightedLinearity: weightedLinearity,
   129→      weightedRange: weightedRange,
   130→      totalScore: totalScore,
   131→    );
   132→  }
   133→
   134→  _Reg _linReg(List<double> x, List<double> y) {
   135→    final n = x.length;
   136→    final meanX = x.reduce((a, b) => a + b) / n;
   137→    final meanY = y.reduce((a, b) => a + b) / n;
   138→
   139→    var num = 0.0, den = 0.0;
   140→    for (var i = 0; i < n; i++) {
   141→      final dx = x[i] - meanX;
   142→      final dy = y[i] - meanY;
   143→      num += dx * dy;
   144→      den += dx * dx;
   145→    }
   146→    final slope = den == 0 ? 0.0 : num / den;
   147→    final intercept = meanY - slope * meanX;
   148→
   149→    return _Reg(slope, intercept);
   150→  }
   151→
   152→  /// 線形回帰直線からの平均二乗誤差を計算
   153→  double _calculateMeanSquaredErrorFromRegression(
   154→      List<double> t, List<double> z, _Reg reg) {
   155→    if (t.length != z.length || t.isEmpty) return double.infinity;
   156→
   157→    var sumSquaredDeviations = 0.0;
   158→    for (var i = 0; i < t.length; i++) {
   159→      final predicted = reg.slope * t[i] + reg.intercept;
   160→      final deviation = z[i] - predicted;
   161→      sumSquaredDeviations += deviation * deviation;
   162→    }
   163→
   164→    return sumSquaredDeviations / t.length; // 平均二乗誤差（MSE）
   165→  }
   166→
   167→  /// 軌道の直線性スコアを計算（平均二乗誤差で評価）
   168→  double _calculateLinearityScore(double mse) {
   169→    // 単位スケールで正規化されたMSEを指数関数でスコア化
   170→    // exp(-α·normalizedMSE) 型で外れ値に対して滑らかなスコア変換
   171→    if (mse <= 0) return 1.0; // MSEが0なら満点
   172→
   173→    // MSEを単位スケールの二乗で正規化
   174→    final normalizedMSE = mse / (p.unitScale * p.unitScale);
   175→
   176→    // 指数関数によるスコア変換: score = exp(-α·normalizedMSE)
   177→    return exp(-p.linearityAlpha * normalizedMSE);
   178→  }
   179→
   180→  /// S_range計算（13m合格ライン、18.44m満点の片側指数モデル）
   181→  double _calculateSRange(double dz) {
   182→    if (dz < p.zMin) {
   183→      return 0;
   184→    }
   185→
   186→    if (dz >= p.zMax) {
   187→      // 投球距離を超えたら満点
   188→      return 1.0;
   189→    }
   190→
   191→    // 合格ライン～投球距離の指数補間
   192→    final k = -log(1 - p.targetSaturation) / (p.zMax - p.zMin);
   193→    return 1 - exp(-k * (dz - p.zMin));
   194→  }
   195→
   196→  /// 検出フレーム数から密度スコアを計算（15枚で0.1、目標フレーム数で目標密度）
   197→  double _calculateDensityScore(double n) {
   198→    if (n < p.nMinimum) return 0.0;
   199→    if (n >= p.nTarget) return p.densityTarget;
   200→
   201→    // 対数モデル: score = 0.1 + (densityTarget - 0.1) * (1 - exp(-k * (n - nMinimum)))
   202→    // 最低フレーム数で0.1、目標フレーム数で目標密度になるように調整
   203→    const double k = 0.15;
   204→    const double baseScore = 0.1;
   205→    final double scaleFactor = p.densityTarget - baseScore;
   206→
   207→    return baseScore + scaleFactor * (1 - exp(-k * (n - p.nMinimum)));
   208→  }
   209→}
   210→
   211→class _Reg {
   212→  final double slope, intercept;
   213→  const _Reg(this.slope, this.intercept);
   214→}
   215→

