/// {@category Utils}
library;

// Dart imports:
import 'dart:math';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball_info.dart';

/// チューニングパラメータ
class QScoreParams {
  final double wDensity, wLinearity, wRange;
  final double nTarget, densityTarget;
  final double nMinimum;
  final double zMin, zMax;
  final double targetSaturation;
  final double unitScale; // 単位スケール（メートル基準）
  final double linearityAlpha; // 直線性スコアのα値

  const QScoreParams({
    this.wDensity = 0.4,
    this.wLinearity = 0.4,
    this.wRange = 0.2,
    this.nTarget = 35.0, // 物理的最大検出フレーム数（35フレーム）
    this.densityTarget = 0.95, // 密度スコア用：35フレームでの目標密度（95%）
    this.nMinimum = 15.0, // 最低検出フレーム数（15フレーム）
    this.zMin = 13.0, // 合格ライン（13m）
    this.zMax = 18.44, // 満点ライン（18.44m）
    this.targetSaturation = 0.95, // 範囲スコア用：18.44mでの目標飽和率
    this.unitScale = 1.0, // 単位スケール（1.0 = メートル）
    this.linearityAlpha = 1.5, // MSE感度パラメータ(適当な値であり変更可能)
  });
}

/// Q-Score詳細結果
class QScoreDetails {
  final double sDensity;
  final double sLinearity;
  final double sRange;
  final double weightedDensity;
  final double weightedLinearity;
  final double weightedRange;
  final double totalScore;

  const QScoreDetails({
    required this.sDensity,
    required this.sLinearity,
    required this.sRange,
    required this.weightedDensity,
    required this.weightedLinearity,
    required this.weightedRange,
    required this.totalScore,
  });
}

/// Q-Score 計算器
class BallQualityScorer {
  final QScoreParams p;
  const BallQualityScorer([this.p = const QScoreParams()]);

  /// 単一のBallInfoからQ-Score詳細を計算する
  QScoreDetails? calculateQScoreDetailsForBall(BallInfo ballInfo) {
    final positions = ballInfo.positions;
    if (positions == null || positions.isEmpty) return null;

    // z座標とtime座標を抽出（nullでないもののみ）
    final List<double> z = [];
    final List<double> t = [];

    for (final pos in positions) {
      if (pos.z != null && pos.time != null) {
        z.add(pos.z!);
        t.add(pos.time!);
      }
    }

    if (z.length != t.length || z.isEmpty) return null;

    return _calculateQScoreDetails(z, t);
  }

  /// z座標とtime座標のリストからQ-Score詳細を計算する
  QScoreDetails _calculateQScoreDetails(List<double> z, List<double> t) {
    if (z.length != t.length || z.isEmpty) {
      return const QScoreDetails(
        sDensity: 0.0,
        sLinearity: 0.0,
        sRange: 0.0,
        weightedDensity: 0.0,
        weightedLinearity: 0.0,
        weightedRange: 0.0,
        totalScore: 0.0,
      );
    }

    // 1. 検出密度（15枚で10%、35枚で95%のlog補完）
    final n = z.length;
    final sDensity = _calculateDensityScore(n.toDouble());

    // 2. 軌道の直線性（平均二乗誤差で評価）
    final reg = _linReg(t, z);
    final mse = _calculateMeanSquaredErrorFromRegression(t, z, reg);
    final sLinearity = _calculateLinearityScore(mse);

    // 3. z 軸変位
    final dz = z.reduce(max) - z.reduce(min);
    final sRange = _calculateSRange(dz);

    // 各スコアの最小値を0にクランプ
    final clampedSDensity = sDensity.clamp(0.0, 1.0);
    final clampedSLinearity = sLinearity.clamp(0.0, 1.0);
    final clampedSRange = sRange.clamp(0.0, 1.0);

    // 重み付けスコア
    final weightedDensity = p.wDensity * clampedSDensity;
    final weightedLinearity = p.wLinearity * clampedSLinearity;
    final weightedRange = p.wRange * clampedSRange;

    // 総合スコア（0–100）
    final totalScore =
        (weightedDensity + weightedLinearity + weightedRange) * 100;

    return QScoreDetails(
      sDensity: clampedSDensity,
      sLinearity: clampedSLinearity,
      sRange: clampedSRange,
      weightedDensity: weightedDensity,
      weightedLinearity: weightedLinearity,
      weightedRange: weightedRange,
      totalScore: totalScore,
    );
  }

  _Reg _linReg(List<double> x, List<double> y) {
    final n = x.length;
    final meanX = x.reduce((a, b) => a + b) / n;
    final meanY = y.reduce((a, b) => a + b) / n;

    var num = 0.0, den = 0.0;
    for (var i = 0; i < n; i++) {
      final dx = x[i] - meanX;
      final dy = y[i] - meanY;
      num += dx * dy;
      den += dx * dx;
    }
    final slope = den == 0 ? 0.0 : num / den;
    final intercept = meanY - slope * meanX;

    return _Reg(slope, intercept);
  }

  /// 線形回帰直線からの平均二乗誤差を計算
  double _calculateMeanSquaredErrorFromRegression(
      List<double> t, List<double> z, _Reg reg) {
    if (t.length != z.length || t.isEmpty) return double.infinity;

    var sumSquaredDeviations = 0.0;
    for (var i = 0; i < t.length; i++) {
      final predicted = reg.slope * t[i] + reg.intercept;
      final deviation = z[i] - predicted;
      sumSquaredDeviations += deviation * deviation;
    }

    return sumSquaredDeviations / t.length; // 平均二乗誤差（MSE）
  }

  /// 軌道の直線性スコアを計算（平均二乗誤差で評価）
  double _calculateLinearityScore(double mse) {
    // 単位スケールで正規化されたMSEを指数関数でスコア化
    // exp(-α·normalizedMSE) 型で外れ値に対して滑らかなスコア変換
    if (mse <= 0) return 1.0; // MSEが0なら満点

    // MSEを単位スケールの二乗で正規化
    final normalizedMSE = mse / (p.unitScale * p.unitScale);

    // 指数関数によるスコア変換: score = exp(-α·normalizedMSE)
    return exp(-p.linearityAlpha * normalizedMSE);
  }

  /// S_range計算（13m合格ライン、18.44m満点の片側指数モデル）
  double _calculateSRange(double dz) {
    if (dz < p.zMin) {
      return 0;
    }

    if (dz >= p.zMax) {
      // 投球距離を超えたら満点
      return 1.0;
    }

    // 合格ライン～投球距離の指数補間
    final k = -log(1 - p.targetSaturation) / (p.zMax - p.zMin);
    return 1 - exp(-k * (dz - p.zMin));
  }

  /// 検出フレーム数から密度スコアを計算（15枚で0.1、目標フレーム数で目標密度）
  double _calculateDensityScore(double n) {
    if (n < p.nMinimum) return 0.0;
    if (n >= p.nTarget) return p.densityTarget;

    // 対数モデル: score = 0.1 + (densityTarget - 0.1) * (1 - exp(-k * (n - nMinimum)))
    // 最低フレーム数で0.1、目標フレーム数で目標密度になるように調整
    const double k = 0.15;
    const double baseScore = 0.1;
    final double scaleFactor = p.densityTarget - baseScore;

    return baseScore + scaleFactor * (1 - exp(-k * (n - p.nMinimum)));
  }
}

class _Reg {
  final double slope, intercept;
  const _Reg(this.slope, this.intercept);
}

