   199→  ///
   200→  /// So we need to call getBall to complete the BallInfo even though we already have BallInfo from getResourceDetail in [_initializeRemoteResourceData].
   201→  Future<Result<Failure, BallInfo>> _performBallInfoFetch(int ballId) async {
   202→    final methodFc = _fc.category('GCBI');
